 1→-- Add agent_session entity for coding agent session tracking
 2→-- and subtask_of relation for task hierarchy.
 3→-- Required for MCP coding agent integration (PLAN.md Layer 1 & 2).
 4→
 5→BEGIN TRANSACTION;
 6→
 7→-- Agent session entity: logs each coding agent session as a graph node
 8→DEFINE TABLE OVERWRITE agent_session SCHEMAFULL;
 9→DEFINE FIELD agent ON agent_session TYPE string;
10→DEFINE FIELD started_at ON agent_session TYPE datetime;
11→DEFINE FIELD ended_at ON agent_session TYPE option<datetime>;
12→DEFINE FIELD workspace ON agent_session TYPE record<workspace>;
13→DEFINE FIELD project ON agent_session TYPE record<project>;
14→DEFINE FIELD task_id ON agent_session TYPE option<record<task>>;
15→DEFINE FIELD summary ON agent_session TYPE option<string>;
16→DEFINE FIELD decisions_made ON agent_session TYPE option<array<record<decision>>>;
17→DEFINE FIELD questions_asked ON agent_session TYPE option<array<record<question>>>;
18→DEFINE FIELD tasks_progressed ON agent_session TYPE option<array<object>>;
19→DEFINE FIELD tasks_progressed[*].task_id ON agent_session TYPE record<task>;
20→DEFINE FIELD tasks_progressed[*].from_status ON agent_session TYPE string;
21→DEFINE FIELD tasks_progressed[*].to_status ON agent_session TYPE string;
22→DEFINE FIELD files_changed ON agent_session TYPE option<array<object>>;
23→DEFINE FIELD files_changed[*].path ON agent_session TYPE string;
24→DEFINE FIELD files_changed[*].change_type ON agent_session TYPE string
25→  ASSERT $value IN ["created", "modified", "deleted"];
26→DEFINE FIELD created_at ON agent_session TYPE datetime;
27→DEFINE INDEX agent_session_workspace ON agent_session FIELDS workspace;
28→DEFINE INDEX agent_session_project ON agent_session FIELDS project;
29→DEFINE INDEX agent_session_started_at ON agent_session FIELDS started_at;
30→
31→-- Subtask relation: task -> task hierarchy
32→DEFINE TABLE OVERWRITE subtask_of TYPE RELATION IN task OUT task SCHEMAFULL;
33→DEFINE FIELD added_at ON subtask_of TYPE datetime;
34→
35→-- Session relations: agent_session -> entities it produced/touched
36→DEFINE TABLE OVERWRITE produced TYPE RELATION IN agent_session OUT decision SCHEMAFULL;
37→DEFINE FIELD added_at ON produced TYPE datetime;
38→
39→DEFINE TABLE OVERWRITE asked TYPE RELATION IN agent_session OUT question SCHEMAFULL;
40→DEFINE FIELD added_at ON asked TYPE datetime;
41→
42→DEFINE TABLE OVERWRITE progressed TYPE RELATION IN agent_session OUT task SCHEMAFULL;
43→DEFINE FIELD from_status ON progressed TYPE string;
44→DEFINE FIELD to_status ON progressed TYPE string;
45→DEFINE FIELD added_at ON progressed TYPE datetime;
46→
47→COMMIT TRANSACTION;
