  1→/**
  2→ * useAgentSession -- SSE subscription hook for agent session state.
  3→ *
  4→ * Opens an EventSource when given an active sessionId + streamUrl.
  5→ * Exposes AgentSessionState: status, filesChanged, startedAt,
  6→ * stallWarning, connectionError.
  7→ *
  8→ * Pure core: reduceAgentSessionEvent handles all state transitions.
  9→ * Effect boundary: useEffect manages EventSource lifecycle + stall timer.
 10→ */
 11→
 12→import { useCallback, useEffect, useRef, useState } from "react";
 13→import type {
 14→  AgentStatusEvent,
 15→  AgentFileChangeEvent,
 16→  AgentStallWarningEvent,
 17→  AgentTokenEvent,
 18→  AgentPromptEvent,
 19→} from "../../shared/contracts";
 20→
 21→// ---------------------------------------------------------------------------
 22→// Types
 23→// ---------------------------------------------------------------------------
 24→
 25→export type AgentSessionStatus =
 26→  | "spawning"
 27→  | "active"
 28→  | "idle"
 29→  | "completed"
 30→  | "aborted"
 31→  | "error";
 32→
 33→export type OutputEntryToken = { kind: "token"; text: string };
 34→export type OutputEntryFileChange = {
 35→  kind: "file_change";
 36→  file: string;
 37→  changeType: "created" | "modified" | "deleted";
 38→};
 39→export type OutputEntryPrompt = { kind: "prompt"; text: string };
 40→
 41→export type OutputEntry =
 42→  | OutputEntryToken
 43→  | OutputEntryFileChange
 44→  | OutputEntryPrompt;
 45→
 46→export type AgentSessionState = {
 47→  status: AgentSessionStatus;
 48→  filesChanged: number;
 49→  startedAt: string;
 50→  lastEventAt?: string;
 51→  stallWarning?: { lastEventAt: string; stallDurationSeconds: number };
 52→  error?: string;
 53→  connectionError?: string;
 54→  outputEntries: OutputEntry[];
 55→};
 56→
 57→// Events the reducer handles (subset of StreamEvent relevant to agent sessions)
 58→type AgentEvent =
 59→  | AgentStatusEvent
 60→  | AgentFileChangeEvent
 61→  | AgentStallWarningEvent
 62→  | AgentTokenEvent
 63→  | AgentPromptEvent;
 64→
 65→// ---------------------------------------------------------------------------
 66→// Constants
 67→// ---------------------------------------------------------------------------
 68→
 69→export const STALL_TIMEOUT_MS = 30_000;
 70→
 71→// ---------------------------------------------------------------------------
 72→// Pure core: state reducer
 73→// ---------------------------------------------------------------------------
 74→
 75→export function createInitialState(startedAt: string): AgentSessionState {
 76→  return {
 77→    status: "spawning",
 78→    filesChanged: 0,
 79→    startedAt,
 80→    outputEntries: [],
 81→  };
 82→}
 83→
 84→export function isTerminalStatus(status: AgentSessionStatus): boolean {
 85→  return status === "completed" || status === "aborted" || status === "error";
 86→}
 87→
 88→export function reduceAgentSessionEvent(
 89→  state: AgentSessionState,
 90→  event: AgentEvent,
 91→): AgentSessionState {
 92→  const now = new Date().toISOString();
 93→
 94→  switch (event.type) {
 95→    case "agent_status":
 96→      return {
 97→        ...state,
 98→        status: event.status,
 99→        lastEventAt: now,
100→        stallWarning: undefined,
101→        error: event.error,
102→      };
103→
104→    case "agent_file_change":
105→      return {
106→        ...state,
107→        filesChanged: state.filesChanged + 1,
108→        lastEventAt: now,
109→        stallWarning: undefined,
110→        outputEntries: [
111→          ...state.outputEntries,
112→          { kind: "file_change", file: event.file, changeType: event.changeType },
113→        ],
114→      };
115→
116→    case "agent_stall_warning":
117→      return {
118→        ...state,
119→        lastEventAt: now,
120→        stallWarning: {
121→          lastEventAt: event.lastEventAt,
122→          stallDurationSeconds: event.stallDurationSeconds,
123→        },
124→      };
125→
126→    case "agent_token":
127→      return {
128→        ...state,
129→        lastEventAt: now,
130→        stallWarning: undefined,
131→        outputEntries: [
132→          ...state.outputEntries,
133→          { kind: "token", text: event.token },
134→        ],
135→      };
136→
137→    case "agent_prompt":
138→      return {
139→        ...state,
140→        lastEventAt: now,
141→        stallWarning: undefined,
142→        outputEntries: [
143→          { kind: "prompt", text: event.text },
144→        ],
145→      };
146→  }
147→}
148→
149→// ---------------------------------------------------------------------------
150→// Hook return type
151→// ---------------------------------------------------------------------------
152→
153→export type UseAgentSessionReturn = {
154→  state: AgentSessionState;
155→  close: () => void;
156→};
157→
158→// ---------------------------------------------------------------------------
159→// Hook: effect boundary (EventSource lifecycle + stall timer)
160→// ---------------------------------------------------------------------------
161→
162→export function useAgentSession(
163→  streamUrl: string | undefined,
164→  startedAt: string,
165→): UseAgentSessionReturn {
166→  const [state, setState] = useState<AgentSessionState>(() =>
167→    createInitialState(startedAt),
168→  );
169→  const eventSourceRef = useRef<EventSource | undefined>(undefined);
170→  const stallTimerRef = useRef<ReturnType<typeof setTimeout> | undefined>(undefined);
171→
172→  // Timer lifecycle: clearStallTimer is stable (no deps). resetStallTimer depends only on
173→  // clearStallTimer, so it is also stable. Both use stallTimerRef (a ref, not state) to avoid
174→  // stale closures. setState updater form ensures state reads are always current.
175→  const clearStallTimer = useCallback(() => {
176→    if (stallTimerRef.current !== undefined) {
177→      clearTimeout(stallTimerRef.current);
178→      stallTimerRef.current = undefined;
179→    }
180→  }, []);
181→
182→  const resetStallTimer = useCallback(() => {
183→    clearStallTimer();
184→    stallTimerRef.current = setTimeout(() => {
185→      setState((prev) => ({
186→        ...prev,
187→        stallWarning: {
188→          lastEventAt: prev.lastEventAt ?? prev.startedAt,
189→          stallDurationSeconds: STALL_TIMEOUT_MS / 1000,
190→        },
191→      }));
192→    }, STALL_TIMEOUT_MS);
193→  }, [clearStallTimer]);
194→
195→  useEffect(() => {
196→    if (!streamUrl) return;
197→
198→    const eventSource = new EventSource(streamUrl);
199→    eventSourceRef.current = eventSource;
200→
201→    // SSE registry sends unnamed events (data-only, no event: field).
202→    // Use onmessage and dispatch on the parsed type.
203→    eventSource.onmessage = (e) => {
204→      resetStallTimer();
205→
206→      try {
207→        const data = JSON.parse(e.data);
208→        const eventType = data.type as string | undefined;
209→        if (!eventType) return;
210→
211→        const event: AgentEvent = data as AgentEvent;
212→        setState((prev) => reduceAgentSessionEvent(prev, event));
213→
214→        // Close on terminal status
215→        if (eventType === "agent_status" && isTerminalStatus(data.status)) {
216→          eventSource.close();
217→          clearStallTimer();
218→        }
219→      } catch {
220→        // Malformed event data -- state not updated but stall timer is reset
221→        console.warn("Failed to parse SSE event data");
222→      }
223→    };
224→
225→    eventSource.onerror = () => {
226→      eventSource.close();
227→      clearStallTimer();
228→      setState((prev) => ({
229→        ...prev,
230→        status: "error",
231→        connectionError: "Connection lost",
232→      }));
233→    };
234→
235→    // Start stall timer
236→    resetStallTimer();
237→
238→    return () => {
239→      eventSource.close();
240→      eventSourceRef.current = undefined;
241→      clearStallTimer();
242→    };
243→  }, [streamUrl, resetStallTimer, clearStallTimer]);
244→
245→  const close = useCallback(() => {
246→    if (eventSourceRef.current) {
247→      eventSourceRef.current.close();
248→      eventSourceRef.current = undefined;
249→    }
250→    clearStallTimer();
251→  }, [clearStallTimer]);
252→
253→  return { state, close };
254→}
255→

  1→import { ToolLoopAgent, Output, stepCountIs } from "ai";
  2→import { z } from "zod";
  3→import { ENTITY_CATEGORIES, ENTITY_PRIORITIES, type ExtractedEntity, type ExtractedRelationship, type SubagentTrace, type SubagentTraceStep } from "../../../shared/contracts";
  4→import type { ChatToolDeps, ChatToolExecutionContext } from "../../tools/types";
  5→import { buildPmSystemPrompt } from "./prompt";
  6→import { createPmTools } from "./tools";
  7→import { createTelemetryConfig } from "../../telemetry/ai-telemetry";
  8→import { FUNCTION_IDS } from "../../telemetry/function-ids";
  9→
 10→const workItemSuggestionSchema = z
 11→  .object({
 12→    kind: z.enum(["task", "feature", "project"]),
 13→    title: z.string().min(1),
 14→    rationale: z.string().min(1),
 15→    category: z.enum(["none", ...ENTITY_CATEGORIES]),
 16→    project: z.enum(["none"]).or(z.string().min(1)),
 17→    priority: z.enum(["none", ...ENTITY_PRIORITIES]),
 18→    possible_duplicate: z.enum(["none"]).or(
 19→      z.object({
 20→        id: z.string().min(1),
 21→        name: z.string().min(1),
 22→        similarity: z.number().min(0).max(1),
 23→      }),
 24→    ),
 25→  })
 26→  .transform((v) => ({
 27→    ...v,
 28→    category: v.category === "none" ? undefined : v.category,
 29→    project: v.project === "none" ? undefined : v.project,
 30→    priority: v.priority === "none" ? undefined : v.priority,
 31→    possible_duplicate: v.possible_duplicate === "none" ? undefined : v.possible_duplicate,
 32→  }));
 33→
 34→const pmAgentResultSchema = z.object({
 35→  summary: z.string().min(1),
 36→  suggestions: z.array(workItemSuggestionSchema),
 37→  updated: z.array(
 38→    z.object({
 39→      existing_id: z.string().min(1),
 40→      title: z.string().min(1),
 41→      changes: z.string().min(1),
 42→    }),
 43→  ),
 44→  discarded: z.array(
 45→    z.object({
 46→      title: z.string().min(1),
 47→      reason: z.string().min(1),
 48→    }),
 49→  ),
 50→  observations_created: z.array(z.string().min(1)),
 51→});
 52→
 53→export type WorkItemSuggestion = z.infer<typeof workItemSuggestionSchema>;
 54→export type PmAgentResult = z.infer<typeof pmAgentResultSchema>;
 55→
 56→export type PmAgentOutput = PmAgentResult & {
 57→  extracted_entities: ExtractedEntity[];
 58→  extracted_relationships: ExtractedRelationship[];
 59→  trace: SubagentTrace;
 60→};
 61→
 62→export type PmAgentInput = {
 63→  deps: ChatToolDeps & { pmAgentModel: any };
 64→  context: ChatToolExecutionContext;
 65→  intent: "plan_work" | "check_status" | "organize" | "track_dependencies";
 66→  conversationContext: string;
 67→};
 68→
 69→const INTENT_INSTRUCTIONS: Record<PmAgentInput["intent"], string> = {
 70→  check_status: "Primary action: call get_project_status when a project scope is available.",
 71→  plan_work: "Primary action: for net-new items use create_work_item; for edits/renames to existing items use edit_work_item. You MUST call the appropriate tool before generating output. Create projects FIRST in their own tool call step before creating their features/tasks. Only use suggest_work_items when items are vague or you need duplicate analysis against many existing entities.",
 72→  track_dependencies: "Primary action: identify blockers/dependencies and create observations for high-risk paths.",
 73→  organize: "Primary action: organize work into clear, deduplicated next steps. When moving items between projects, use search_entities to find existing items, then move_items_to_project to reassign them. Do NOT recreate items that already exist.",
 74→};
 75→
 76→export async function runPmAgent(input: PmAgentInput): Promise<PmAgentOutput> {
 77→  const system = await buildPmSystemPrompt({
 78→    surreal: input.deps.surreal,
 79→    workspaceRecord: input.context.workspaceRecord,
 80→  });
 81→
 82→  const agent = new ToolLoopAgent({
 83→    id: "pm-agent",
 84→    model: input.deps.pmAgentModel,
 85→    instructions: system,
 86→    tools: createPmTools(input.deps),
 87→    output: Output.object({ schema: pmAgentResultSchema }),
 88→    experimental_telemetry: createTelemetryConfig(FUNCTION_IDS.PM_AGENT),
 89→    experimental_context: { ...input.context, actor: "pm_agent" as const, humanPresent: input.context.humanPresent ?? true },
 90→    stopWhen: stepCountIs(6),
 91→  });
 92→
 93→  const startedAt = performance.now();
 94→
 95→  const result = await agent.generate({
 96→    prompt: [
 97→      "You are handling a PM request.",
 98→      `Intent: ${input.intent}`,
 99→      INTENT_INSTRUCTIONS[input.intent],
100→      "IMPORTANT: You MUST call your tools (create_work_item, edit_work_item, suggest_work_items, etc.) BEFORE generating your final output. Do NOT skip tool calls — your output summary must reflect actual tool execution results.",
101→      "Context:",
102→      input.conversationContext,
103→    ].join("\n"),
104→  });
105→
106→  const totalDurationMs = Math.round(performance.now() - startedAt);
107→
108→  if (!result.output) {
109→    throw new Error("pm agent did not produce structured output");
110→  }
111→
112→  const extracted_entities: ExtractedEntity[] = [];
113→  const extracted_relationships: ExtractedRelationship[] = [];
114→  const traceSteps: SubagentTraceStep[] = [];
115→
116→  for (const step of result.steps) {
117→    if (step.text?.trim()) {
118→      traceSteps.push({ type: "text", text: step.text.trim() });
119→    }
120→
121→    for (const toolResult of step.toolResults) {
122→      traceSteps.push({
123→        type: "tool_call",
124→        toolName: toolResult.toolName,
125→        argsJson: JSON.stringify(toolResult.input),
126→        resultJson: JSON.stringify(toolResult.output),
127→      });
128→
129→      const res = toolResult.output as Record<string, unknown> | undefined;
130→      if (res) {
131→        if (Array.isArray(res.extracted_entities)) {
132→          extracted_entities.push(...(res.extracted_entities as ExtractedEntity[]));
133→        }
134→        if (Array.isArray(res.extracted_relationships)) {
135→          extracted_relationships.push(...(res.extracted_relationships as ExtractedRelationship[]));
136→        }
137→      }
138→    }
139→  }
140→
141→  return {
142→    ...result.output,
143→    extracted_entities,
144→    extracted_relationships,
145→    trace: {
146→      agentId: "pm_agent",
147→      intent: input.intent,
148→      steps: traceSteps,
149→      totalDurationMs,
150→    },
151→  };
152→}
