  7→export type AuthorityAction =
  8→  | "create_decision"
  9→  | "confirm_decision"
 10→  | "create_task"
 11→  | "complete_task"
 12→  | "create_observation"
 13→  | "acknowledge_observation"
 14→  | "resolve_observation"
 15→  | "create_question"
 16→  | "create_suggestion";
 17→
 18→export type AuthorityPermission = "auto" | "provisional" | "propose" | "blocked";
 19→
 20→export type AuthorizedContext = {
 21→  context: ChatToolExecutionContext;
 22→  permission: AuthorityPermission;
 23→};
 24→
 25→export class AuthorityError extends Error {
 26→  constructor(
 27→    public readonly permission: "propose" | "blocked",
 28→    public readonly action: AuthorityAction,
 29→    public readonly agentType: AgentType,
 30→  ) {
 31→    const verb = permission === "blocked" ? "not authorized" : "can only propose";
 32→    super(`${agentType} is ${verb} for action: ${action}`);
 33→    this.name = "AuthorityError";
 34→  }
 35→}
 36→
 37→const ACTOR_DEFAULT_AGENT_TYPE: Partial<Record<string, AgentType>> = {
 38→  pm_agent: "management",
 39→  analytics_agent: "observer",
 40→};
 41→
 42→export async function checkAuthority(input: {
 43→  surreal: Surreal;
 44→  agentType: AgentType;
 45→  action: AuthorityAction;
 46→  workspaceRecord?: RecordId<"workspace", string>;
 47→  identityRecord?: RecordId<"identity", string>;
 48→}): Promise<AuthorityPermission> {
 49→  // 0. Human bypass: if identity type is human, always allow
 50→  if (input.identityRecord) {
 51→    const [identityRows] = await input.surreal.query<[Array<{ type: string; role?: string }>]>(
 52→      "SELECT type, role FROM $record;",
 53→      { record: input.identityRecord },
 54→    );
 55→
 56→    if (identityRows.length > 0 && identityRows[0].type === "human") {
 57→      return "auto";
 58→    }
 59→
 60→    const identityRole = identityRows.length > 0 ? identityRows[0].role : undefined;
 61→
 62→    // 1. Per-identity override via authorized_to relation
 63→    const [overrideRows] = await input.surreal.query<[Array<{ permission: string }>]>(
 64→      `SELECT permission FROM authorized_to
 65→       WHERE in = $identity
 66→       AND out.action = $action
 67→       LIMIT 1;`,
 68→      { identity: input.identityRecord, action: input.action },
 69→    );
 70→
 71→    if (overrideRows.length > 0) {
 72→      return overrideRows[0].permission as AuthorityPermission;
 73→    }
 74→
 75→    // 2. Role-based resolution: use identity.role to match authority_scope.agent_type
 76→    if (identityRole) {
 77→      if (input.workspaceRecord) {
 78→        const [wsRoleRows] = await input.surreal.query<[Array<{ permission: string }>]>(
 79→          "SELECT permission FROM authority_scope WHERE agent_type = $role AND action = $action AND workspace = $workspace LIMIT 1;",
 80→          { role: identityRole, action: input.action, workspace: input.workspaceRecord },
 81→        );
 82→        if (wsRoleRows.length > 0) {
 83→          return wsRoleRows[0].permission as AuthorityPermission;
 84→        }
 85→      }
 86→
 87→      const [globalRoleRows] = await input.surreal.query<[Array<{ permission: string }>]>(
 88→        "SELECT permission FROM authority_scope WHERE agent_type = $role AND action = $action AND workspace IS NONE LIMIT 1;",
 89→        { role: identityRole, action: input.action },
 90→      );
 91→      if (globalRoleRows.length > 0) {
 92→        return globalRoleRows[0].permission as AuthorityPermission;
 93→      }
 94→    }
 95→  }
 96→
 97→  // 3. Agent-type based resolution (existing behavior)
 98→  if (input.workspaceRecord) {
 99→    const [wsRows] = await input.surreal.query<[Array<{ permission: string }>]>(
100→      "SELECT permission FROM authority_scope WHERE agent_type = $agentType AND action = $action AND workspace = $workspace LIMIT 1;",
101→      {
102→        agentType: input.agentType,
103→        action: input.action,
104→        workspace: input.workspaceRecord,
105→      },
106→    );
107→
108→    if (wsRows.length > 0) {
109→      return wsRows[0].permission as AuthorityPermission;
110→    }
111→  }
112→
113→  // 4. Fall back to global default (workspace IS NONE)
114→  const [globalRows] = await input.surreal.query<[Array<{ permission: string }>]>(
115→    "SELECT permission FROM authority_scope WHERE agent_type = $agentType AND action = $action AND workspace IS NONE LIMIT 1;",
116→    { agentType: input.agentType, action: input.action },
117→  );
118→
119→  if (globalRows.length > 0) {
120→    return globalRows[0].permission as AuthorityPermission;
121→  }
122→
123→  // 5. Fail-safe: no row = blocked
124→  return "blocked";
125→}
