57→async function findExistingIdentity(
58→  surreal: Surreal,
59→  workspaceRecord: RecordId<"workspace", string>,
60→  type: IdentityType,

 60→  type: IdentityType,
 61→  role: string,
 62→): Promise<RecordId<"identity", string> | undefined> {
