227→/**
228→ * Resolves the target entity for an observation by querying the observes edge.
229→ */
230→async function resolveObservationTarget(
231→  surreal: Surreal,
232→  observationId: string,
233→): Promise<{ table: string; id: string } | undefined> {
234→  const obsRecord = new RecordId("observation", observationId);
235→  const result = await surreal.query<[Array<{ out: RecordId }>]>(
236→    `SELECT out FROM observes WHERE in = $obs LIMIT 1;`,
237→    { obs: obsRecord },
238→  );
239→  const edge = result[0]?.[0];
240→  if (edge?.out instanceof RecordId) {
241→    return { table: edge.out.table.name, id: edge.out.id as string };
242→  }
243→  return undefined;
244→}
