269→/**
270→ * Creates a new agent session for a matched agent, marking it as "spawning".
271→ */
272→async function createActivatedSession(
273→  surreal: Surreal,
274→  match: { agentType: string; workspaceId: string; observationId: string },
275→): Promise<string> {
276→  const sessionId = `sess-${crypto.randomUUID()}`;
277→  const sessionRecord = new RecordId("agent_session", sessionId);
278→  const workspaceRecord = new RecordId("workspace", match.workspaceId);
279→  const observationRecord = new RecordId("observation", match.observationId);
280→
281→  await surreal.query(`CREATE $sess CONTENT $content;`, {
282→    sess: sessionRecord,
283→    content: {
284→      agent: match.agentType,
285→      started_at: new Date(),
286→      workspace: workspaceRecord,
287→      orchestrator_status: "spawning",
288→      source: "activator",
289→      triggered_by: observationRecord,
290→      created_at: new Date(),
291→    },
292→  });
293→
294→  return sessionId;
295→}
