411→// ---------------------------------------------------------------------------
412→// Agent Activator Handler (Side-Effect Shell)
413→// ---------------------------------------------------------------------------
414→
415→/**
416→ * Creates the agent activator POST endpoint handler.
417→ *
418→ * Called by SurrealDB DEFINE EVENT webhook on observation CREATE.
419→ * Parses the webhook payload, checks loop dampener, checks active coverage,
420→ * uses LLM to classify which agents should handle the observation,
421→ * starts new agent sessions for matched agents.
422→ */
423→export function createAgentActivatorHandler(deps: AgentActivatorDeps) {
424→  const { surreal, loopDampener, inflight, classifierModel, onAgentActivation, internalWebhookSecret } = deps;
425→
426→  return async function handleObservationWebhook(request: Request): Promise<Response> {
427→    // Validate shared secret if configured
428→    const authHeader = request.headers.get("authorization") ?? undefined;
429→    if (!validateWebhookSecret(authHeader, internalWebhookSecret)) {
430→      return new Response("unauthorized", { status: 401 });
431→    }
432→
433→    const body = await request.json().catch(() => undefined);
434→    const payload = parseWebhookPayload(body);
435→
436→    if (!payload) {
437→      return new Response("invalid payload", { status: 200 });
438→    }
439→
440→    // Process async — return 200 immediately (same pattern as observer-route.ts)
441→    inflight.track(
442→      processObservation(payload).catch((err) => {
443→        log.error("activator.process_failed", "Failed to process observation", {
444→          observationId: payload.observation_id,
445→          error: err instanceof Error ? err.message : String(err),
446→        });
447→      }),
448→    );
449→
450→    return new Response("accepted", { status: 200 });
451→  };
452→
453→  async function processObservation(payload: ObservationWebhookPayload): Promise<void> {
454→    const { observation_id, workspace, text, severity, source_agent } = payload;
455→
456→    // Resolve target entity for dampener keying and active coverage check
457→    const target = await resolveObservationTarget(surreal, observation_id);
458→    const dampenerEntityKey = target ? `${target.table}:${target.id}` : observation_id;
459→    const dampenerEvent = buildDampenerEvent(workspace, dampenerEntityKey, source_agent);
460→    const dampenerResult = loopDampener.record(dampenerEvent);
461→
462→    if (dampenerResult.dampened) {
463→      await createDampeningMetaObservation(
464→        surreal,
465→        workspace,
466→        dampenerEntityKey,
467→        source_agent,
468→      ).catch((err) => {
469→        log.error("activator.dampening_meta_failed", "Failed to create dampening meta-observation", {
470→          workspaceId: workspace,
471→          entityId: dampenerEntityKey,
472→          error: err instanceof Error ? err.message : String(err),
473→        });
474→      });
475→      return;
476→    }
477→
478→    // Skip if target entity already has an active agent session — proxy handles it
479→    if (target) {
480→      const covered = await hasActiveCoverage(surreal, target, workspace);
481→      if (covered) {
482→        log.info("activator.skipped_active_coverage", "Skipping observation — target has active agent session", {
483→          observationId: observation_id,
484→          target: `${target.table}:${target.id}`,
485→          workspaceId: workspace,
486→        });
487→        return;
488→      }
489→    }
490→
491→    // Load registered agents for this workspace
492→    const agents = await loadWorkspaceAgents(surreal, workspace);
493→    if (agents.length === 0) {
494→      log.warn("activator.no_agents", "No agents registered with descriptions in workspace", {
495→          workspaceId: workspace,
496→          observationId: observation_id,
497→        });
498→      return;
499→    }
500→
501→    // LLM classification: which agents should handle this observation?
502→    const prompt = buildClassificationPrompt({ text, severity }, agents);
503→    const classification = await generateObject({
504→      model: classifierModel,
505→      schema: classificationSchema,
506→      prompt,
507→    });
508→
509→    const activations = classification.object.activations;
510→    log.info("activator.classified", "LLM classified agents for observation", {
511→      observationId: observation_id,
512→      agentCount: activations.length,
513→      workspaceId: workspace,
514→    });
515→
516→    // Validate agent IDs against registered agents
517→    const agentMap = new Map(agents.map((a) => [a.agentId, a]));
518→    const validActivations: Array<{ agent: RegisteredAgent; reason: string }> = [];
519→    const hallucinatedIds: string[] = [];
520→
521→    for (const activation of activations) {
522→      const agent = agentMap.get(activation.agent_id);
523→      if (!agent) {
524→        log.warn("activator.hallucinated_agent", "LLM returned unknown agent_id", {
525→          agentId: activation.agent_id,
526→          observationId: observation_id,
527→          workspaceId: workspace,
528→        });
529→        hallucinatedIds.push(activation.agent_id);
530→        continue;
531→      }
532→      validActivations.push({ agent, reason: activation.reason });
533→    }
534→
535→    // Create governance observation for hallucinated agent IDs
536→    if (hallucinatedIds.length > 0) {
537→      await createHallucinationObservation(
538→        surreal,
539→        workspace,
540→        observation_id,
541→        hallucinatedIds,
542→      ).catch((err) => {
543→        log.error("activator.hallucination_obs_failed", "Failed to create hallucination observation", {
544→          observationId: observation_id,
545→          workspaceId: workspace,
546→          error: err instanceof Error ? err.message : String(err),
547→        });
548→      });
549→    }
550→
551→    // Record the routing decision for conflict/warning observations (governance trail)
552→    if (severity === "conflict" || severity === "warning") {
553→      await createActivationDecision(
554→        surreal,
555→        workspace,
556→        observation_id,
557→        text,
558→        severity,
559→        validActivations.map((v) => ({ agentType: v.agent.agentType, reason: v.reason })),
560→      ).catch((err) => {
561→        log.error("activator.decision_failed", "Failed to create activation decision", {
562→          observationId: observation_id,
563→          workspaceId: workspace,
564→          error: err instanceof Error ? err.message : String(err),
565→        });
566→      });
567→    }
568→
569→    // Start agent sessions for matched agents
570→    for (const { agent, reason } of validActivations) {
571→      try {
572→        await createActivatedSession(surreal, {
573→          agentType: agent.agentType,
574→          workspaceId: workspace,
575→          observationId: observation_id,
576→        });
577→      } catch (err) {
578→        log.error("activator.session_failed", "Failed to create activated session", {
579→          agentType: agent.agentType,
580→          observationId: observation_id,
581→          workspaceId: workspace,
582→          error: err instanceof Error ? err.message : String(err),
583→        });
584→        continue; // skip activation callback — no DB record exists
585→      }
586→
587→      onAgentActivation({
588→        agentId: agent.agentId,
589→        agentType: agent.agentType,
590→        workspaceId: workspace,
591→        reason,
592→        observationId: observation_id,
593→        observationText: text,
594→      });
595→    }
596→  }
597→}
