  1→/**
  2→ * Sandbox Agent Adapter -- port types and adapter factories.
  3→ *
  4→ * Port types define the contract for interacting with a SandboxAgent server.
  5→ * The adapter abstracts at the SDK level: one factory wraps the real SDK instance,
  6→ * another provides a test-injectable mock with overridable behavior.
  7→ *
  8→ * Real SDK types are re-exported for use by callers without direct SDK dependency.
  9→ */
 10→import type {
 11→  SandboxAgent,
 12→  Session,
 13→  SessionCreateRequest,
 14→  SessionEvent,
 15→  SessionEventListener,
 16→  SessionPermissionRequest,
 17→  PermissionRequestListener,
 18→  PermissionReply,
 19→} from "sandbox-agent";
 20→
 21→// Derive prompt types from Session's method signature (not directly exported by sandbox-agent)
 22→type PromptInput = Parameters<Session["prompt"]>[0];
 23→type PromptResponse = Awaited<ReturnType<Session["prompt"]>>;
 24→
 25→// Re-export SDK types used at port boundaries
 26→export type {
 27→  SessionEvent,
 28→  SessionEventListener,
 29→  SessionPermissionRequest,
 30→  PermissionRequestListener,
 31→  PermissionReply,
 32→  PromptResponse,
 33→};
 34→
 35→// ── Port Types ──
 36→
 37→/**
 38→ * Brain-owned session creation request.
 39→ * Extends the SDK's SessionCreateRequest with env for passing environment
 40→ * variables (e.g. ANTHROPIC_BASE_URL, X-Brain-Auth) into the sandbox.
 41→ */
 42→export type CreateSessionRequest = SessionCreateRequest & {
 43→  env?: Record<string, string>;
 44→};
 45→
 46→/**
 47→ * MCP server config for remote MCP servers.
 48→ * Matches the sandbox-agent SDK's McpServerConfig remote variant.
 49→ */
 50→export type McpServerConfig = {
 51→  readonly type: "remote";
 52→  readonly url: string;
 53→  readonly transport?: string;
 54→  readonly headers?: Record<string, string>;
 55→};
 56→
 57→export type SessionHandle = {
 58→  id: string;
 59→  prompt: (
 60→    messages: PromptInput,
 61→  ) => Promise<PromptResponse>;
 62→  onEvent: (listener: SessionEventListener) => () => void;
 63→  onPermissionRequest: (listener: PermissionRequestListener) => () => void;
 64→  respondPermission: (permissionId: string, reply: PermissionReply) => Promise<void>;
 65→};
 66→
 67→export type SandboxAgentAdapter = {
 68→  createSession: (request: CreateSessionRequest) => Promise<SessionHandle>;
 69→  resumeSession: (sessionId: string) => Promise<SessionHandle>;
 70→  destroySession: (sessionId: string) => Promise<void>;
 71→  /**
 72→   * Configure a remote MCP server on the SDK, keyed by (directory, name).
 73→   * Call before createSession -- the session inherits MCP configs matching its cwd.
 74→   * Each session uses a unique worktree path as cwd, so configs are effectively per-session.
 75→   */
 76→  setMcpConfig: (directory: string, name: string, config: McpServerConfig) => Promise<void>;
 77→  /** Exposed for test assertion -- last request passed to createSession. */
 78→  lastCreateSessionRequest?: CreateSessionRequest;
 79→};
 80→
 81→// ── Production Adapter Factory ──
 82→
 83→function wrapSession(session: Session): SessionHandle {
 84→  return {
 85→    id: session.id,
 86→    prompt: (messages) => session.prompt(messages),
 87→    onEvent: (listener) => session.onEvent(listener),
 88→    onPermissionRequest: (listener) => session.onPermissionRequest(listener),
 89→    respondPermission: (permissionId, reply) => session.respondPermission(permissionId, reply),
 90→  };
 91→}
 92→
 93→/**
 94→ * Creates a production adapter backed by a real SandboxAgent SDK instance.
 95→ * The SDK instance should be created via `SandboxAgent.start()` or `SandboxAgent.connect()`.
 96→ */
 97→export function createSandboxAgentAdapter(
 98→  sdk: SandboxAgent,
 99→): SandboxAgentAdapter {
100→  return {
101→    createSession: async (request) => {
102→      const { env: _env, ...sdkRequest } = request;
103→      const session = await sdk.createSession(sdkRequest);
104→      return wrapSession(session);
105→    },
106→    resumeSession: async (sessionId) => {
107→      const session = await sdk.resumeSession(sessionId);
108→      return wrapSession(session);
109→    },
110→    destroySession: async (sessionId) => {
111→      await sdk.destroySession(sessionId);
112→    },
113→    setMcpConfig: async (directory, name, config) => {
114→      await sdk.setMcpConfig({ directory, mcpName: name }, config);
115→    },
116→  };
117→}
118→
119→// ── Mock Adapter Factory ──
120→
121→export function createMockAdapter(
122→  overrides?: Partial<SandboxAgentAdapter>,
123→): SandboxAgentAdapter {
124→  const sessions = new Map<string, SessionHandle>();
125→  const destroyed = new Set<string>();
126→  let lastCreateSessionRequest: CreateSessionRequest | undefined;
127→  const mcpConfigs = new Map<string, Map<string, McpServerConfig>>();
128→
129→  const createHandle = (id: string): SessionHandle => ({
130→    id,
131→    prompt: async () => {
132→      if (destroyed.has(id)) {
133→        throw new Error(`Session ${id} has been destroyed`);
134→      }
135→      return { stopReason: "end_turn" as const } as PromptResponse;
136→    },
137→    onEvent: () => () => {},
138→    onPermissionRequest: () => () => {},
139→    respondPermission: async () => {
140→      if (destroyed.has(id)) {
141→        throw new Error(`Session ${id} has been destroyed`);
142→      }
143→    },
144→  });
145→
146→  return {
147→    get lastCreateSessionRequest() {
148→      return lastCreateSessionRequest;
149→    },
150→    createSession: async (request) => {
151→      lastCreateSessionRequest = request;
152→      const id = `session-${crypto.randomUUID()}`;
153→      const handle = createHandle(id);
154→      sessions.set(id, handle);
155→      return handle;
156→    },
157→    resumeSession: async (sessionId) => {
158→      if (destroyed.has(sessionId)) {
159→        throw new Error(`Session ${sessionId} has been destroyed`);
160→      }
161→      const existing = sessions.get(sessionId);
162→      if (existing) {
163→        return existing;
164→      }
165→      const handle = createHandle(sessionId);
166→      sessions.set(sessionId, handle);
167→      return handle;
168→    },
169→    destroySession: async (sessionId) => {
170→      sessions.delete(sessionId);
171→      destroyed.add(sessionId);
172→    },
173→    setMcpConfig: async (directory, name, config) => {
174→      const key = `${directory}:${name}`;
175→      if (!mcpConfigs.has(key)) mcpConfigs.set(key, new Map());
176→      mcpConfigs.get(key)!.set(name, config);
177→    },
178→    ...overrides,
179→  };
180→}
