  1→/**
  2→ * Sandbox event bridge: transforms SandboxAgent SessionEvents into Brain
  3→ * StreamEvent variants and forwards them to the SSE registry.
  4→ *
  5→ * Pure transform function (translateSessionEvent) + effectful bridge handle
  6→ * (createSandboxEventBridge) that manages the event forwarding lifecycle.
  7→ *
  8→ * SessionEvent.payload is an ACP JSON-RPC message. The bridge extracts
  9→ * session/update notifications and maps their content to Brain stream events.
 10→ *
 11→ * This module handles SandboxAgent events (different schema from event-bridge.ts
 12→ * which handles Claude SDK messages). Both coexist until R1 migration completes.
 13→ */
 14→import type {
 15→  AgentTokenEvent,
 16→  AgentStatusEvent,
 17→  StreamEvent,
 18→} from "../../shared/contracts";
 19→import type { SessionEvent } from "./sandbox-adapter";
 20→import { log } from "../telemetry/logger";
 21→
 22→// Re-export for callers that reference the old SandboxEvent name
 23→export type SandboxEvent = SessionEvent;
 24→
 25→// ---------------------------------------------------------------------------
 26→// Port: dependencies as function signatures
 27→// ---------------------------------------------------------------------------
 28→
 29→export type SandboxEventBridgeDeps = {
 30→  emitEvent: (streamId: string, event: StreamEvent) => void;
 31→  updateLastEventAt: (sessionId: string) => Promise<void>;
 32→  updateSessionStatus: (
 33→    sessionId: string,
 34→    status: AgentStatusEvent["status"],
 35→    error?: string,
 36→  ) => Promise<void>;
 37→  notifyStallDetector: (sessionId: string) => void;
 38→};
 39→
 40→// ---------------------------------------------------------------------------
 41→// Bridge handle
 42→// ---------------------------------------------------------------------------
 43→
 44→export type SandboxEventBridgeHandle = {
 45→  handleEvent: (event: SessionEvent) => void;
 46→  stop: () => void;
 47→};
 48→
 49→// ---------------------------------------------------------------------------
 50→// ACP JSON-RPC payload helpers (untyped extraction from AnyMessage)
 51→// ---------------------------------------------------------------------------
 52→
 53→type AcpPayload = {
 54→  method?: string;
 55→  params?: {
 56→    sessionId?: string;
 57→    update?: {
 58→      sessionUpdate?: string;
 59→      content?: { type?: string; text?: string };
 60→      toolCallId?: string;
 61→      name?: string;
 62→      [key: string]: unknown;
 63→    };
 64→    [key: string]: unknown;
 65→  };
 66→  result?: unknown;
 67→  error?: unknown;
 68→  [key: string]: unknown;
 69→};
 70→
 71→function extractSessionUpdate(payload: AcpPayload): { sessionUpdate: string; [key: string]: unknown } | undefined {
 72→  if (payload.method === "session/update" && payload.params?.update) {
 73→    return payload.params.update as { sessionUpdate: string; [key: string]: unknown };
 74→  }
 75→  return undefined;
 76→}
 77→
 78→// ---------------------------------------------------------------------------
 79→// Pure transform: SessionEvent -> StreamEvent | undefined
 80→// ---------------------------------------------------------------------------
 81→
 82→function translateToolCall(
 83→  sessionId: string,
 84→  update: { name?: string; toolCallId?: string; [key: string]: unknown },
 85→): AgentTokenEvent {
 86→  const toolName = (update.name as string) ?? "unknown";
 87→  return {
 88→    type: "agent_token",
 89→    sessionId,
 90→    token: `Tool Call: ${toolName}`,
 91→  };
 92→}
 93→
 94→function translateMessageChunk(
 95→  sessionId: string,
 96→  update: { content?: { text?: string }; [key: string]: unknown },
 97→): AgentTokenEvent | undefined {
 98→  const text = update.content?.text;
 99→  if (!text) return undefined;
100→  return {
101→    type: "agent_token",
102→    sessionId,
103→    token: text,
104→  };
105→}
106→
107→function translateToolCallUpdate(
108→  sessionId: string,
109→  update: { title?: string; status?: string; [key: string]: unknown },
110→): AgentTokenEvent | undefined {
111→  if (typeof update.title === "string" && update.title.trim().length > 0) {
112→    return {
113→      type: "agent_token",
114→      sessionId,
115→      token: `Tool Update: ${update.title}`,
116→    };
117→  }
118→  if (typeof update.status === "string" && update.status.trim().length > 0) {
119→    return {
120→      type: "agent_token",
121→      sessionId,
122→      token: `Tool Status: ${update.status}`,
123→    };
124→  }
125→  return undefined;
126→}
127→
128→export function translateSessionEvent(
129→  event: SessionEvent,
130→): StreamEvent | undefined {
131→  const payload = event.payload as AcpPayload;
132→  const update = extractSessionUpdate(payload);
133→
134→  if (!update) {
135→    // Not a session/update notification -- may be a response or other message.
136→    // Check if it's a prompt response (which has result.stopReason)
137→    if (payload.result && typeof payload.result === "object") {
138→      const result = payload.result as { stopReason?: string };
139→      if (result.stopReason) {
140→        return {
141→          type: "agent_status",
142→          sessionId: event.sessionId,
143→          status: "idle" as AgentStatusEvent["status"],
144→        };
145→      }
146→    }
147→    return undefined;
148→  }
149→
150→  switch (update.sessionUpdate) {
151→    case "tool_call":
152→      return translateToolCall(event.sessionId, update);
153→
154→    case "tool_call_update":
155→      return translateToolCallUpdate(event.sessionId, update);
156→
157→    case "agent_message_chunk":
158→    case "user_message_chunk":
159→    case "agent_thought_chunk":
160→      return translateMessageChunk(event.sessionId, update);
161→
162→    default:
163→      // Other update types (plan, config_option_update, etc.) are informational
164→      // and don't map to Brain stream events yet.
165→      return undefined;
166→  }
167→}
168→
169→// ---------------------------------------------------------------------------
170→// Bridge handle factory
171→// ---------------------------------------------------------------------------
172→
173→export function createSandboxEventBridge(
174→  deps: SandboxEventBridgeDeps,
175→  streamId: string,
176→  sessionId: string,
177→): SandboxEventBridgeHandle {
178→  let stopped = false;
179→
180→  const handleEvent = (event: SessionEvent): void => {
181→    if (stopped) return;
182→
183→    const streamEvent = translateSessionEvent(event);
184→    if (!streamEvent) return;
185→
186→    deps.emitEvent(streamId, streamEvent);
187→
188→    if (streamEvent.type === "agent_status") {
189→      deps.updateSessionStatus(sessionId, streamEvent.status, streamEvent.error).catch((err) => {
190→        log.warn("sandbox-event-bridge", "Failed to update orchestrator status", {
191→          sessionId,
192→          status: streamEvent.status,
193→          error: String(err),
194→        });
195→      });
196→    }
197→
198→    // Fire-and-forget: update last_event_at for stall detection
199→    deps.updateLastEventAt(sessionId).catch((err) => {
200→      log.warn("sandbox-event-bridge", "Failed to update last_event_at", {
201→        sessionId,
202→        error: String(err),
203→      });
204→    });
205→
206→    // Notify stall detector of activity
207→    deps.notifyStallDetector(sessionId);
208→  };
209→
210→  return {
211→    handleEvent,
212→    stop(): void {
213→      stopped = true;
214→    },
215→  };
216→}
