 80→async function handleWorkspaceMine(deps: ServerDependencies, request: Request): Promise<Response> {
 81→  const session = await deps.auth.api.getSession({ headers: request.headers });
 82→  if (!session?.user?.id) {
 83→    return jsonError("authentication required", 401);
 84→  }
 85→
 86→  const personRecord = new RecordId("person", session.user.id);
 87→
 88→  const [rows] = await deps.surreal.query<
 89→    [Array<{ workspace_id: RecordId<"workspace", string>; workspace_name: string }>]
 90→  >(
 91→    `SELECT out.id AS workspace_id, out.name AS workspace_name
 92→     FROM member_of
 93→     WHERE in IN (SELECT VALUE in FROM identity_person WHERE out = $person)
 94→     LIMIT 1;`,
 95→    { person: personRecord },
 96→  );
 97→
 98→  if (!rows.length) {
 99→    return jsonResponse({ workspaceId: undefined }, 200);
100→  }
101→
102→  return jsonResponse({
103→    workspaceId: rows[0].workspace_id.id as string,
104→    workspaceName: rows[0].workspace_name,
105→  }, 200);
106→}
