352→async function loadWorkspaceSeeds(
353→  deps: ServerDependencies,
354→  workspaceRecord: RecordId<"workspace", string>,
355→  limit: number,
356→): Promise<OnboardingSeedItem[]> {
357→  const [edgeRows] = await deps.surreal
358→    .query<[ProvenanceEdgeRow[]]>(
359→      [
360→        "SELECT id, `in`, out, confidence, extracted_at",
361→        "FROM extraction_relation",
362→        "WHERE `in` IN array::concat(",
363→        "  (SELECT VALUE id FROM message WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)),",
364→        "  (SELECT VALUE id FROM document_chunk WHERE workspace = $workspace)",
365→        ")",
366→        "ORDER BY extracted_at DESC",
367→        "LIMIT $limit;",
368→      ].join(" "),
369→      {
370→        workspace: workspaceRecord,
371→        limit,
372→      },
373→    )
374→    .collect<[ProvenanceEdgeRow[]]>();
375→
376→  const items: OnboardingSeedItem[] = [];
377→
378→  for (const edge of edgeRows) {
379→    const entityText = await readEntityText(deps.surreal, edge.out);
380→    if (!entityText) {
381→      continue;
382→    }
383→
384→    const sourceTable = edge.in.table.name;
385→    const entityTable = edge.out.table.name;
386→    const sourceKind = (sourceTable === "document_chunk" ? "document_chunk" : "message") as SourceKind;
387→    const sourceLabel = await readSourceLabel(deps, edge.in);
388→
389→    items.push({
390→      id: edge.out.id as string,
391→      kind: entityTable as EntityKind,
392→      text: entityText,
393→      confidence: edge.confidence,
394→      sourceKind,
395→      sourceId: edge.in.id as string,
396→      ...(sourceLabel ? { sourceLabel } : {}),
397→    });
398→  }
399→
400→  return items;
401→}
402→
403→async function readSourceLabel(deps: ServerDependencies, sourceRecord: SourceRecord): Promise<string | undefined> {
404→  const sourceTable = sourceRecord.table.name;
405→  if (sourceTable === "message") {
406→    const row = await deps.surreal.select<{ text: string }>(sourceRecord);
407→    if (!row) {
408→      return undefined;
409→    }
410→    return row.text.slice(0, 140);
411→  }
412→
413→  const chunk = await deps.surreal.select<{
414→    section_heading?: string;
415→    document: RecordId<"document", string>;
416→  }>(sourceRecord);
417→
418→  if (!chunk) {
419→    return undefined;
420→  }
421→
422→  const document = await deps.surreal.select<{ name: string }>(chunk.document);
423→  if (!document) {
424→    return chunk.section_heading;
425→  }
426→
427→  if (chunk.section_heading) {
428→    return `${document.name} · ${chunk.section_heading}`;
429→  }
430→
431→  return document.name;
432→}
