114→// ---------------------------------------------------------------------------
115→// BM25 + Recency Ranking (02-01: pure functions)
116→// ---------------------------------------------------------------------------
117→
118→const DEFAULT_RECENCY_HALFLIFE_HOURS = 168; // 1 week
119→
120→/**
121→ * Compute exponential recency decay factor.
122→ * decayFactor = exp(-ageHours / halflife)
123→ *
124→ * Returns 1.0 for zero or negative age (future timestamps treated as fresh).
125→ */
126→export function computeRecencyDecay(ageHours: number, halflife: number): number {
127→  if (ageHours <= 0) return 1.0;
128→  return Math.exp(-ageHours / halflife);
129→}
130→
131→/**
132→ * Compute final context score: BM25 relevance weighted by recency decay.
133→ * finalScore = bm25Score * exp(-ageHours / halflife)
134→ */
135→export function computeFinalScore(
136→  bm25Score: number,
137→  updatedAt: string,
138→  now: Date,
139→  halflife: number,
140→): number {
141→  const ageMs = now.getTime() - new Date(updatedAt).getTime();
142→  const ageHours = ageMs / (1000 * 60 * 60);
143→  return bm25Score * computeRecencyDecay(ageHours, halflife);
144→}
145→
146→/**
147→ * Rank BM25 context candidates by combined relevance and recency.
148→ * Pure pipeline: map to final scores, sort descending.
149→ */
150→export function rankByBm25WithRecency(
151→  candidates: Bm25ContextCandidate[],
152→  now: Date,
153→  halflife: number = DEFAULT_RECENCY_HALFLIFE_HOURS,
154→): RankedCandidate[] {
155→  return candidates
156→    .map((c) => ({
157→      id: c.id,
158→      type: c.type,
159→      text: c.text,
160→      score: computeFinalScore(c.bm25Score, c.updatedAt, now, halflife),
161→    }))
162→    .sort((a, b) => b.score - a.score);
163→}
