193→
194→export function buildBrainContextXml(
195→  selected: RankedCandidate[],
196→  workspaceSettings?: WorkspaceSettings,
197→): string {
198→  const sections: string[] = [];
199→
200→  if (workspaceSettings?.enforcementMode) {
201→    sections.push(
202→      `<workspace-settings>\n  <evidence-enforcement>${workspaceSettings.enforcementMode}</evidence-enforcement>\n</workspace-settings>`,
203→    );
204→  }
205→
206→  const decisions = selected.filter((c) => c.type === "decision");
207→  const learnings = selected.filter((c) => c.type === "learning");
208→  const observations = selected.filter((c) => c.type === "observation");
209→
210→  if (decisions.length > 0) {
211→    const items = decisions.map((d) => `  <item>${d.text}</item>`).join("\n");
212→    sections.push(`<decisions>\n${items}\n</decisions>`);
213→  }
214→
215→  if (learnings.length > 0) {
216→    const items = learnings.map((l) => `  <item>${l.text}</item>`).join("\n");
217→    sections.push(`<learnings>\n${items}\n</learnings>`);
218→  }
219→
220→  if (observations.length > 0) {
221→    const items = observations.map((o) => `  <item>${o.text}</item>`).join("\n");
222→    sections.push(`<observations>\n${items}\n</observations>`);
223→  }
224→
225→  if (sections.length === 0) return "";
226→
227→  return `<brain-context>\n${sections.join("\n")}\n</brain-context>`;
228→}
