231→// System Prompt Injection
232→// ---------------------------------------------------------------------------
233→
234→export function injectBrainContext(
235→  originalSystem: SystemPrompt,
236→  brainContextXml: string,
237→): InjectionResult {
238→  if (!brainContextXml) {
239→    return {
240→      system: originalSystem ?? "",
241→      injected: false,
242→      tokensEstimated: 0,
243→      decisionsCount: 0,
244→      learningsCount: 0,
245→      observationsCount: 0,
246→    };
247→  }
248→
249→  const tokensEstimated = estimateTokenCount(brainContextXml);
250→
251→  // Count items in XML (by counting <item> tags per section)
252→  const decisionsCount = (brainContextXml.match(/<decisions>[\s\S]*?<\/decisions>/)?.[0]?.match(/<item>/g) ?? []).length;
253→  const learningsCount = (brainContextXml.match(/<learnings>[\s\S]*?<\/learnings>/)?.[0]?.match(/<item>/g) ?? []).length;
254→  const observationsCount = (brainContextXml.match(/<observations>[\s\S]*?<\/observations>/)?.[0]?.match(/<item>/g) ?? []).length;
255→
256→  if (Array.isArray(originalSystem)) {
257→    // Array-form: append brain-context as additional text block with cache_control: ephemeral
258→    const enriched = [
259→      ...originalSystem,
260→      {
261→        type: "text",
262→        text: brainContextXml,
263→        cache_control: { type: "ephemeral" },
264→      },
265→    ];
266→
267→    return {
268→      system: enriched,
269→      injected: true,
270→      tokensEstimated,
271→      decisionsCount,
272→      learningsCount,
273→      observationsCount,
274→    };
275→  }
276→
277→  if (typeof originalSystem === "string") {
278→    // String-form: append brain-context after original text
279→    return {
280→      system: `${originalSystem}\n\n${brainContextXml}`,
281→      injected: true,
282→      tokensEstimated,
283→      decisionsCount,
284→      learningsCount,
285→      observationsCount,
286→    };
287→  }
288→
289→  // No original system prompt: use brain-context as system prompt
290→  return {
291→    system: brainContextXml,
292→    injected: true,
293→    tokensEstimated,
294→    decisionsCount,
295→    learningsCount,
296→    observationsCount,
297→  };
298→}
