300→// ---------------------------------------------------------------------------
301→// Recent Changes Injection into System Prompt (04-02: pure)
302→// ---------------------------------------------------------------------------
303→
304→/**
305→ * Injects recent changes XML into a system prompt with correct ordering:
306→ * - <urgent-context> is injected BEFORE <brain-context>
307→ * - <context-update> is injected AFTER <brain-context>
308→ *
309→ * For array-form system prompts, each block becomes a separate text element
310→ * with cache_control: ephemeral.
311→ */
312→export function injectRecentChanges(
313→  system: SystemPrompt,
314→  recentChangesXml: string,
315→): InjectionResult["system"] {
316→  if (!recentChangesXml) return system ?? "";
317→
318→  // Extract urgent-context and context-update blocks from the XML
319→  const urgentMatch = recentChangesXml.match(/<urgent-context>[\s\S]*?<\/urgent-context>/);
320→  const updateMatch = recentChangesXml.match(/<context-update>[\s\S]*?<\/context-update>/);
321→
322→  const urgentBlock = urgentMatch?.[0] ?? "";
323→  const updateBlock = updateMatch?.[0] ?? "";
324→
325→  if (!urgentBlock && !updateBlock) return system ?? "";
326→
327→  if (Array.isArray(system)) {
328→    const result = [...system];
329→
330→    // Find the brain-context block index for insertion ordering
331→    const brainContextIdx = result.findIndex(
332→      (block) => typeof block.text === "string" && block.text.includes("<brain-context>"),
333→    );
334→
335→    if (brainContextIdx >= 0) {
336→      // Insert urgent BEFORE brain-context, update AFTER
337→      if (updateBlock) {
338→        result.splice(brainContextIdx + 1, 0, {
339→          type: "text",
340→          text: updateBlock,
341→          cache_control: { type: "ephemeral" },
342→        });
343→      }
344→      if (urgentBlock) {
345→        result.splice(brainContextIdx, 0, {
346→          type: "text",
347→          text: urgentBlock,
348→          cache_control: { type: "ephemeral" },
349→        });
350→      }
351→    } else {
352→      // No brain-context block -- append both at end (urgent first, then update)
353→      if (urgentBlock) {
354→        result.push({ type: "text", text: urgentBlock, cache_control: { type: "ephemeral" } });
355→      }
356→      if (updateBlock) {
357→        result.push({ type: "text", text: updateBlock, cache_control: { type: "ephemeral" } });
358→      }
359→    }
360→
361→    return result;
362→  }
363→
364→  if (typeof system === "string") {
365→    // String-form: find <brain-context> position for ordering
366→    const brainContextPos = system.indexOf("<brain-context>");
367→
368→    if (brainContextPos >= 0) {
369→      const brainContextEnd = system.indexOf("</brain-context>");
370→      const afterBrainContext = brainContextEnd >= 0
371→        ? brainContextEnd + "</brain-context>".length
372→        : system.length;
373→
374→      const before = system.slice(0, brainContextPos);
375→      const brainSection = system.slice(brainContextPos, afterBrainContext);
376→      const after = system.slice(afterBrainContext);
377→
378→      const parts = [before.trimEnd()];
379→      if (urgentBlock) parts.push(urgentBlock);
380→      parts.push(brainSection);
381→      if (updateBlock) parts.push(updateBlock);
382→      parts.push(after.trimStart());
383→
384→      return parts.filter(Boolean).join("\n\n");
385→    }
386→
387→    // No brain-context -- append both
388→    const parts = [system];
389→    if (urgentBlock) parts.push(urgentBlock);
390→    if (updateBlock) parts.push(updateBlock);
391→    return parts.join("\n\n");
392→  }
393→
394→  // No existing system prompt -- combine blocks
395→  const parts: string[] = [];
396→  if (urgentBlock) parts.push(urgentBlock);
397→  if (updateBlock) parts.push(updateBlock);
398→  return parts.join("\n\n");
399→}

